/**
 * A generic MinPriorityQueue implementation optimized for this problem's needs.
 * It stores items [priority1, priority2, data...] and prioritizes based on the tuple (priority1, priority2).
 * Comparison: (p1_1, p1_2) < (p2_1, p2_2) if p1_1 < p2_1 or (p1_1 == p2_1 and p1_2 < p2_2).
 */
class MinPriorityQueue {
    constructor() {
        // Stores elements as [p1, p2, data...]
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    _compare(i, j) {
        const a = this.heap[i];
        const b = this.heap[j];
        // Compare based on the first priority element (p1)
        if (a[0] !== b[0]) {
            return a[0] - b[0]; // Min heap on p1
        }
        // If p1 is equal, compare based on the second priority element (p2)
        return a[1] - b[1]; // Min heap on p2 (since we store -Color, this achieves Max Color for ties)
    }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    _siftUp(index) {
        let current = index;
        while (current > 0) {
            const parent = Math.floor((current - 1) / 2);
            if (this._compare(current, parent) < 0) {
                this._swap(current, parent);
                current = parent;
            } else {
                break;
            }
        }
    }

    _siftDown(index) {
        let current = index;
        const length = this.heap.length;

        while (true) {
            let left = 2 * current + 1;
            let right = 2 * current + 2;
            let smallest = current;

            if (left < length && this._compare(left, smallest) < 0) {
                smallest = left;
            }

            if (right < length && this._compare(right, smallest) < 0) {
                smallest = right;
            }

            if (smallest !== current) {
                this._swap(current, smallest);
                current = smallest;
            } else {
                break;
            }
        }
    }

    push(item) {
        this.heap.push(item);
        this._siftUp(this.heap.length - 1);
    }

    pop() {
        if (this.isEmpty()) return undefined;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._siftDown(0);
        return root;
    }
}


/**
 * @param {number} n
 * @param {number} m
 * @param {number[][]} sources
 * @return {number[][]}
 */
function solve(n, m, sources) {
    // Grid stores {time: number, color: number} for each cell
    // Initialize time to Infinity, color to 0 (uncolored)
    const grid = Array(n).fill(0).map(() => 
        Array(m).fill(0).map(() => ({ time: Infinity, color: 0 }))
    );

    // Min Priority Queue stores [Time, NegativeColor, r, c]
    // Minimizing NegativeColor maximizes Color for equal Times.
    const pq = new MinPriorityQueue();

    // Directions: up, down, left, right
    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

    // 1. Initialize sources
    for (const [r, c, color] of sources) {
        // If multiple sources are at the same point (though constraints say they aren't, 
        // we handle the general case for robustness)
        if (grid[r][c].time > 0) { 
            grid[r][c].time = 0;
            grid[r][c].color = color;
            // Priority: [Time, -Color, r, c]
            pq.push([0, -color, r, c]);
        } else {
            // Source cell is already initialized by a previous source (shouldn't happen based on constraints)
            // We need to ensure we pick the best initial state if conflicts existed.
            if (color > grid[r][c].color) {
                 grid[r][c].color = color;
                 // Re-add to PQ if color improved (or just push, as time is 0)
                 pq.push([0, -color, r, c]);
            }
        }
    }

    // 2. Run Dijkstra/Multi-Source BFS
    while (!pq.isEmpty()) {
        const [T, NegC, r, c] = pq.pop();
        const C = -NegC;

        // Check for stale entry: if we found a better path already, skip.
        // We must check both time and color because a path found later might have the same time 
        // but a better color, which was handled when it was pushed, but this pop might be outdated 
        // if a subsequent path improved the color at the same time T.
        if (T > grid[r][c].time || (T === grid[r][c].time && C < grid[r][c].color)) {
            continue;
        }

        // Explore neighbors
        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;

            // Check bounds
            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                const T_new = T + 1;
                const C_new = C;

                const T_current = grid[nr][nc].time;
                const C_current = grid[nr][nc].color;

                // Condition 1: Strictly faster arrival time
                if (T_new < T_current) {
                    grid[nr][nc].time = T_new;
                    grid[nr][nc].color = C_new;
                    pq.push([T_new, -C_new, nr, nc]);
                } 
                // Condition 2: Same arrival time, but better color
                else if (T_new === T_current) {
                    if (C_new > C_current) {
                        grid[nr][nc].color = C_new;
                        // Since the color changed, this cell might influence its neighbors 
                        // with a stronger color at the same time step. Re-enqueue.
                        pq.push([T_new, -C_new, nr, nc]);
                    }
                }
            }
        }
    }

    // 3. Format output
    const result = [];
    for (let i = 0; i < n; i++) {
        const row = [];
        for (let j = 0; j < m; j++) {
            row.push(grid[i][j].color);
        }
        result.push(row);
    }

    return result;
}

