    neg_color: Int64,
    r: Int64,
    c: Int64,
}

struct MinPriorityQueue {
    heap: List<State>,

    fn new() -> Self {
        Self { heap: [] }
    }

    fn is_empty(&self) -> Bool {
        self.heap.len == 0
    }

