        self.heap.push(item)
        self._sift_up(self.heap.len - 1)
    }

    fn pop(&mut self) -> Option<State> {
        if self.is_empty() {
            return None
        }
        if self.heap.len == 1 {
            return Some(self.heap.pop().unwrap())
        }

        let root = self.heap[0]
        self.heap[0] = self.heap.pop().unwrap()
        self._sift_down(0)
        Some(root)
    }

