        while index > 0 {
            let parent = (index - 1) / 2
            if self._compare(index, parent) < 0 {
                self._swap(index, parent)
                index = parent
            } else {
                break
            }
        }
    }

    fn _sift_down(&mut self, mut index: Int) {
        let length = self.heap.len
